Batch Config Generator (批量配置生成工具)# This tool allows you to automatically generate repetitive configuration scripts or JSON based on a template. Define variables in your template using the {{{VariableName}}} syntax.
1. Template (模板) Use {{{VariableName}}} to define variables. Example provided below.
{ "name" : "{{{变量1}}}", "ikeVersion" : "V2", "authenticationMode" : 0, "authenticationAlgorithm" : "SHA2-256", "preSharedKey" : "{{{变量2}}}", "encryptionAlgorithm" : "AES-256-CBC", "ikePrf" : "hmac-sha2-256", "integrityAlgorithm" : "hmac-sha2-256", "ikeSaDuration" : 86400, "dhGroup" : "group2", "dpdEnable" : true, "dpdType" : "periodic", "dpdIdleTime" : 30, "dpdTransmitInterval" : 15, "enableLocalId" : true, "localType" : "fqdn", "localId" : "{{{变量3}}}", "enableRemoteId" : false, "securityProtocol" : "ESP", "ahAuthenticationAlgorithm" : null, "espAuthenticationAlgorithm" : "SHA2-256", "espEncryptionAlgorithm" : "NONE", "profilePfs" : "dh-group14" } &lt;div class=&quot;form-group&quot; style=&quot;max-width: 200px;&quot;&gt; &lt;label&gt;2. Loop Count (循环次数 1-300)&lt;/label&gt; &lt;input type=&quot;number&quot; id=&quot;loopCount&quot; min=&quot;1&quot; max=&quot;300&quot; value=&quot;3&quot;&gt; &lt;/div&gt; &lt;div class=&quot;form-group&quot;&gt; &lt;button class=&quot;btn&quot; onclick=&quot;extractVariables()&quot;&gt;3. Extract Variables (提取变量)&lt;/button&gt; &lt;/div&gt; &lt;div id=&quot;variablesSection&quot; style=&quot;display: none;&quot;&gt; &lt;h3 style=&quot;border-bottom: 1px solid #ccc; padding-bottom: 0.5rem;&quot;&gt;4. Variable Values (输入变量列表)&lt;/h3&gt; &lt;p style=&quot;font-size: 0.9em; color: #666;&quot;&gt;Enter one value per line for each variable. The number of lines must be at least equal to the loop count.&lt;/p&gt; &lt;div id=&quot;varListContainer&quot; class=&quot;var-list-container&quot;&gt;&lt;/div&gt; &lt;div id=&quot;errorAlert&quot; class=&quot;alert&quot;&gt;&lt;/div&gt; &lt;div class=&quot;form-group&quot; style=&quot;margin-top: 1.5rem;&quot;&gt; &lt;button class=&quot;btn&quot; onclick=&quot;generateConfig()&quot;&gt;5. Generate Config (生成配置)&lt;/button&gt; &lt;/div&gt; &lt;/div&gt; &lt;div id=&quot;outputSection&quot; class=&quot;form-group&quot; style=&quot;display: none; margin-top: 2rem;&quot;&gt; &lt;h3 style=&quot;border-bottom: 1px solid #ccc; padding-bottom: 0.5rem;&quot;&gt;Output (生成结果)&lt;/h3&gt; &lt;textarea id=&quot;outputResult&quot; rows=&quot;20&quot; readonly style=&quot;background-color: #fff;&quot;&gt;&lt;/textarea&gt; &lt;/div&gt;
